//! precompute-comic-ply — Batch-process all comic-corpus panels into PLY point clouds.
//!
//! Runs the Phyle temporal depth pipeline on every .cleared.png in the corpus,
//! producing a .ply file with RGB + depth-as-Z for each panel.
//!
//! ## Usage
//!
//! ```text
//! precompute-comic-ply --corpus <dir> --out <dir> [--shell 1] [--manifest manifest.json]
//! ```
//!
//! Default shell=1 (9 frames, ~15s/panel at 800x236). Shell 2 = 27 frames, higher quality.
//! Writes a manifest.json listing all generated PLY files with metadata.

use std::env;
use std::fs;
use std::path::{Path, PathBuf};
use std::time::Instant;

use distributed_inference::mesh_depth_field::{build_mesh_depth_field, MeshDepthConfig};
use distributed_inference::mesh_residual_deblur::{
    mesh_residual_deblur_rgb_f32, MeshResidualDeblurConfig,
};
use distributed_inference::phyle_temporal_depth::{
    extract_standing_wave_depth, PhyleTemporalDepthField, TritonPhase,
};

#[derive(serde::Serialize)]
struct PanelManifestEntry {
    stem: String,
    ply_file: String,
    width: u32,
    height: u32,
    point_count: u32,
    mouth_point_count: u32,
    standing_wave_coverage: f32,
    shell: u8,
    elapsed_ms: u64,
}

#[derive(serde::Serialize)]
struct Manifest {
    version: String,
    shell_depth: u8,
    total_panels: usize,
    total_points: u64,
    total_elapsed_ms: u64,
    panels: Vec<PanelManifestEntry>,
}

fn load_image_rgb(path: &Path) -> Result<(Vec<f32>, u32, u32), String> {
    let img = image::open(path)
        .map_err(|e| format!("{}: {e}", path.display()))?
        .to_rgba8();
    let (w, h) = img.dimensions();
    let pix = (w * h) as usize;
    let mut rgb = vec![0.0f32; pix * 3];
    for (i, pixel) in img.pixels().enumerate() {
        rgb[i * 3] = pixel[0] as f32 / 255.0;
        rgb[i * 3 + 1] = pixel[1] as f32 / 255.0;
        rgb[i * 3 + 2] = pixel[2] as f32 / 255.0;
    }
    Ok((rgb, w, h))
}

fn simulate_phase(rgb: &[f32], width: u32, height: u32, phase: TritonPhase) -> Vec<f32> {
    let pix = (width * height) as usize;
    let mut out = vec![0.0f32; pix * 3];
    let (dx, dy): (i32, i32) = match phase {
        TritonPhase::Past => (0, 0),
        TritonPhase::Present => (1, 0),
        TritonPhase::Future => (0, 1),
    };
    for y in 0..height as i32 {
        for x in 0..width as i32 {
            let sx = (x + dx).clamp(0, width as i32 - 1) as usize;
            let sy = (y + dy).clamp(0, height as i32 - 1) as usize;
            let src = (sy * width as usize + sx) * 3;
            let dst = (y as usize * width as usize + x as usize) * 3;
            out[dst] = rgb[src];
            out[dst + 1] = rgb[src + 1];
            out[dst + 2] = rgb[src + 2];
        }
    }
    out
}

/// Detect mouth regions in _why's comic art style.
///
/// _why's characters: dark silhouettes (luma < 0.3) with bright interior features.
/// Eyes = small bright spots in upper face. Mouth = bright feature below eyes.
///
/// Returns a per-pixel mask: 1.0 = mouth, 0.0 = not mouth.
fn detect_mouths(rgb: &[f32], width: u32, height: u32) -> Vec<f32> {
    let w = width as usize;
    let h = height as usize;
    let pix = w * h;
    let mut mouth_mask = vec![0.0f32; pix];

    // Step 1: compute per-pixel luma
    let mut luma = vec![0.0f32; pix];
    for i in 0..pix {
        luma[i] = rgb[i * 3] * 0.2126 + rgb[i * 3 + 1] * 0.7152 + rgb[i * 3 + 2] * 0.0722;
    }

    // Step 2: find dark connected components (character silhouettes)
    // A character region is a contiguous dark area (luma < 0.3) of significant size
    let dark_threshold = 0.3;
    let min_char_area = 200;
    let mut visited = vec![false; pix];
    let mut characters: Vec<(Vec<usize>, u32, u32, u32, u32)> = Vec::new(); // (pixels, min_x, min_y, max_x, max_y)

    for start in 0..pix {
        if visited[start] || luma[start] >= dark_threshold {
            continue;
        }
        // BFS flood fill
        let mut queue = std::collections::VecDeque::new();
        let mut component = Vec::new();
        queue.push_back(start);
        visited[start] = true;
        let mut min_x = (start % w) as u32;
        let mut max_x = min_x;
        let mut min_y = (start / w) as u32;
        let mut max_y = min_y;

        while let Some(pos) = queue.pop_front() {
            component.push(pos);
            let x = (pos % w) as u32;
            let y = (pos / w) as u32;
            min_x = min_x.min(x);
            max_x = max_x.max(x);
            min_y = min_y.min(y);
            max_y = max_y.max(y);

            for (dx, dy) in [(0i32, -1i32), (0, 1), (-1, 0), (1, 0)] {
                let nx = x as i32 + dx;
                let ny = y as i32 + dy;
                if nx >= 0 && nx < w as i32 && ny >= 0 && ny < h as i32 {
                    let ni = ny as usize * w + nx as usize;
                    if !visited[ni] && luma[ni] < dark_threshold {
                        visited[ni] = true;
                        queue.push_back(ni);
                    }
                }
            }
        }

        if component.len() >= min_char_area {
            characters.push((component, min_x, min_y, max_x, max_y));
        }
    }

    // Step 3: for each character, find bright spots inside the dark region
    // and classify the lowest cluster as "mouth"
    for (pixels, _min_x, min_y, _max_x, max_y) in &characters {
        let char_height = max_y - min_y + 1;
        if char_height < 10 {
            continue;
        }

        // Scan for bright pixels inside this dark component's bounding box
        // that are surrounded by dark pixels (interior bright features)
        let mut bright_features: Vec<(usize, u32, u32)> = Vec::new(); // (pixel_idx, x, y)

        for &px in pixels.iter() {
            let x = (px % w) as u32;
            let y = (px / w) as u32;

            // Check 3x3 neighborhood for bright spots
            for dy in -2i32..=2 {
                for dx in -2i32..=2 {
                    let nx = x as i32 + dx;
                    let ny = y as i32 + dy;
                    if nx < 0 || nx >= w as i32 || ny < 0 || ny >= h as i32 {
                        continue;
                    }
                    let ni = ny as usize * w + nx as usize;
                    // Bright pixel surrounded by dark = interior feature (eye or mouth)
                    if luma[ni] > 0.6 {
                        bright_features.push((ni, nx as u32, ny as u32));
                    }
                }
            }
        }

        if bright_features.is_empty() {
            continue;
        }

        // Deduplicate
        bright_features.sort_by_key(|f| f.0);
        bright_features.dedup_by_key(|f| f.0);

        // Find the vertical center of bright features (eyes are typically upper, mouth lower)
        let mean_y =
            bright_features.iter().map(|f| f.2 as f32).sum::<f32>() / bright_features.len() as f32;

        // Mouth = bright features in the lower portion of the feature cluster
        // (below the mean Y of all features, within the character bounds)
        let mouth_y_threshold = mean_y + (max_y - min_y) as f32 * 0.05;

        for (px_idx, _x, y) in &bright_features {
            if *y as f32 > mouth_y_threshold {
                mouth_mask[*px_idx] = 1.0;
                // Expand mouth region slightly (3px radius)
                for dy in -3i32..=3 {
                    for dx in -3i32..=3 {
                        let nx = (*px_idx % w) as i32 + dx;
                        let ny = (*px_idx / w) as i32 + dy;
                        if nx >= 0 && nx < w as i32 && ny >= 0 && ny < h as i32 {
                            let ni = ny as usize * w + nx as usize;
                            mouth_mask[ni] = 1.0;
                        }
                    }
                }
            }
        }
    }

    mouth_mask
}

fn process_panel(
    image_path: &Path,
    out_dir: &Path,
    stem: &str,
    shell_depth: u8,
    depth_config: &MeshDepthConfig,
    deblur_config: &MeshResidualDeblurConfig,
) -> Result<PanelManifestEntry, String> {
    let start = Instant::now();
    let (rgb, width, height) = load_image_rgb(image_path)?;

    let frames_total = 3usize.pow(shell_depth as u32 + 1);
    let mut field = PhyleTemporalDepthField::new(width, height);

    for frame_idx in 0..frames_total {
        let phase = TritonPhase::from_index(frame_idx);
        let phase_rgb = simulate_phase(&rgb, width, height, phase);

        let (depth, _) =
            build_mesh_depth_field(&phase_rgb, width, height, depth_config, None, None)
                .map_err(|e| format!("depth: {e:?}"))?;
        let deblur = mesh_residual_deblur_rgb_f32(&phase_rgb, width, height, deblur_config)
            .map_err(|e| format!("deblur: {e:?}"))?;

        field
            .ingest_frame(&depth.values, &depth.confidence, &deblur.admission)
            .map_err(|e| format!("ingest: {e:?}"))?;
    }

    let sw = extract_standing_wave_depth(&field);

    // Detect mouth regions for lip-sync animation
    let mouth_mask = detect_mouths(&rgb, width, height);

    // Generate PLY: x,y from pixel coords, z from fused depth, RGBA from source + mouth tag
    let mut ply_body = String::new();
    let mut point_count = 0u32;
    let mut mouth_point_count = 0u32;
    let aspect = width as f32 / height as f32;

    for y in 0..height {
        for x in 0..width {
            let i = y as usize * width as usize + x as usize;
            let sw_mask = field.standing_wave_mask[i];
            if sw_mask < 0.1 {
                continue;
            }

            let nx = (x as f32 / width as f32) * 2.0 * aspect - aspect;
            let ny = -((y as f32 / height as f32) * 2.0 - 1.0);
            let nz = (field.fused_depth[i] - 0.5) * 0.4;

            let r = (rgb[i * 3] * 255.0).clamp(0.0, 255.0) as u8;
            let g = (rgb[i * 3 + 1] * 255.0).clamp(0.0, 255.0) as u8;
            let b = (rgb[i * 3 + 2] * 255.0).clamp(0.0, 255.0) as u8;
            let is_mouth = mouth_mask[i] > 0.5;
            let a: u8 = if is_mouth { 255 } else { 0 };
            if is_mouth {
                mouth_point_count += 1;
            }

            ply_body.push_str(&format!(
                "{:.4} {:.4} {:.4} {} {} {} {}\n",
                nx, ny, nz, r, g, b, a
            ));
            point_count += 1;
        }
    }

    let header = format!(
        "ply\nformat ascii 1.0\nelement vertex {}\n\
         property float x\nproperty float y\nproperty float z\n\
         property uchar red\nproperty uchar green\nproperty uchar blue\n\
         property uchar alpha\n\
         end_header\n",
        point_count
    );

    let ply_file = format!("{}.ply", stem);
    let out_path = out_dir.join(&ply_file);
    fs::write(&out_path, format!("{}{}", header, ply_body)).map_err(|e| format!("write: {e}"))?;

    let elapsed = start.elapsed().as_millis() as u64;

    Ok(PanelManifestEntry {
        stem: stem.to_string(),
        ply_file,
        width,
        height,
        point_count,
        mouth_point_count,
        standing_wave_coverage: sw.coverage_ratio,
        shell: field.current_shell,
        elapsed_ms: elapsed,
    })
}

fn main() {
    let args: Vec<String> = env::args().collect();
    let get = |flag: &str| -> Option<String> {
        args.iter()
            .position(|a| a == flag)
            .and_then(|p| args.get(p + 1))
            .cloned()
    };

    let corpus_dir = PathBuf::from(
        get("--corpus").unwrap_or_else(|| "apps/thoth-openai-gateway/comic-corpus".to_string()),
    );
    let out_dir = PathBuf::from(get("--out").unwrap_or_else(|| "/tmp/comic-ply".to_string()));
    let shell: u8 = get("--shell").and_then(|s| s.parse().ok()).unwrap_or(0);
    let manifest_path = PathBuf::from(
        get("--manifest")
            .unwrap_or_else(|| out_dir.join("manifest.json").to_string_lossy().to_string()),
    );

    fs::create_dir_all(&out_dir).expect("create out dir");

    let depth_config = MeshDepthConfig::default();
    let deblur_config = MeshResidualDeblurConfig::default();

    let mut cleared: Vec<PathBuf> = fs::read_dir(&corpus_dir)
        .expect("read corpus")
        .filter_map(|e| e.ok())
        .map(|e| e.path())
        .filter(|p| p.extension().map(|e| e == "png").unwrap_or(false))
        .filter(|p| {
            p.file_name()
                .and_then(|n| n.to_str())
                .map(|n| n.ends_with(".cleared.png"))
                .unwrap_or(false)
        })
        .collect();
    cleared.sort();

    println!("=== PRECOMPUTE COMIC PLY ===");
    println!("  Corpus: {}", corpus_dir.display());
    println!("  Output: {}", out_dir.display());
    println!("  Panels: {}", cleared.len());
    println!(
        "  Shell depth: {} ({} frames per panel)",
        shell,
        3usize.pow(shell as u32 + 1)
    );
    println!();

    let mut manifest = Manifest {
        version: "phyle-comic-ply/v1".to_string(),
        shell_depth: shell,
        total_panels: cleared.len(),
        total_points: 0,
        total_elapsed_ms: 0,
        panels: Vec::new(),
    };

    let total_start = Instant::now();

    for (idx, path) in cleared.iter().enumerate() {
        let stem = path
            .file_name()
            .and_then(|n| n.to_str())
            .and_then(|n| n.strip_suffix(".cleared.png"))
            .unwrap_or("unknown");

        print!("  [{:3}/{}] {} ... ", idx + 1, cleared.len(), stem);

        match process_panel(path, &out_dir, stem, shell, &depth_config, &deblur_config) {
            Ok(entry) => {
                println!(
                    "{}pts {}mouth {:.0}% sw {}ms",
                    entry.point_count,
                    entry.mouth_point_count,
                    entry.standing_wave_coverage * 100.0,
                    entry.elapsed_ms
                );
                manifest.total_points += entry.point_count as u64;
                manifest.total_elapsed_ms += entry.elapsed_ms;
                manifest.panels.push(entry);
            }
            Err(e) => {
                println!("FAILED: {}", e);
            }
        }
    }

    let total_elapsed = total_start.elapsed().as_secs();

    // Write manifest
    let manifest_json = serde_json::to_string_pretty(&manifest).expect("serialize manifest");
    fs::write(&manifest_path, &manifest_json).expect("write manifest");

    println!();
    println!("========================================================================");
    println!(" DONE");
    println!("========================================================================");
    println!(
        "  Panels processed: {}/{}",
        manifest.panels.len(),
        cleared.len()
    );
    println!("  Total points: {}", manifest.total_points);
    println!("  Total time: {}s", total_elapsed);
    println!("  Manifest: {}", manifest_path.display());
}
